const question = $.input.question;
const depth = $.input.reasoningDepth || 'thorough';

const depthGuide = {
  quick: '3-5 reasoning steps, concise analysis',
  thorough: '5-8 reasoning steps, detailed analysis with examples',
  exhaustive: '8-12 reasoning steps, comprehensive analysis with counterarguments'
};
const guide = depthGuide[depth] || depthGuide.thorough;

let prompt = 'You are an AI reasoning specialist. Use explicit chain-of-thought reasoning to work through the given question step by step. Show your complete thinking process.\n\n';
prompt += 'QUESTION: ' + question + '\n';
prompt += 'REASONING DEPTH: ' + depth + ' (' + guide + ')\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Think step by step, labeling each step clearly\n';
prompt += '- Consider multiple perspectives and potential counterarguments\n';
prompt += '- Show when you change your mind or discover new angles\n';
prompt += '- End with a clear conclusion supported by your reasoning\n';
prompt += '- Rate your confidence in the conclusion\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "question": "The original question",\n';
prompt += '  "reasoningSteps": [\n';
prompt += '    { "step": 1, "thought": "First, let me consider...", "insight": "key realization" }\n';
prompt += '  ],\n';
prompt += '  "conclusion": "Final answer based on reasoning",\n';
prompt += '  "confidence": "high/medium/low",\n';
prompt += '  "alternativeViews": ["other perspective worth considering"],\n';
prompt += '  "keyTakeaway": "One-sentence summary"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiReasoning.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { question: $.input.question, reasoningSteps: [{ step: 1, thought: raw, insight: '' }], conclusion: '', confidence: 'medium', alternativeViews: [], keyTakeaway: '' }; }

const ai = $.steps.parseAI.output;
const depth = $.input.reasoningDepth || 'thorough';

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'AI Chain-of-Thought Reasoning', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Question:* ' + (ai.question || $.input.question) } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Depth:*\n' + depth },
  { type: 'mrkdwn', text: '*Confidence:*\n' + (ai.confidence || 'N/A') }
] });
blocks.push({ type: 'divider' });

if (ai.reasoningSteps && ai.reasoningSteps.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*:brain: Reasoning Process:*' } });
  ai.reasoningSteps.slice(0, 10).forEach(s => {
    let stepText = '*Step ' + s.step + ':* ' + (s.thought || '').slice(0, 400);
    if (s.insight) { stepText += '\n:bulb: _' + s.insight + '_'; }
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: stepText } });
  });
}

blocks.push({ type: 'divider' });
const conclusionText = (ai.conclusion || 'No conclusion reached.').slice(0, 2000);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*:white_check_mark: Conclusion:*\n' + conclusionText } });

if (ai.keyTakeaway) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*:dart: Key Takeaway:*\n' + ai.keyTakeaway } });
}

if (ai.alternativeViews && ai.alternativeViews.length > 0) {
  let altText = '*:arrows_counterclockwise: Alternative Views:*\n';
  ai.alternativeViews.slice(0, 3).forEach((v, i) => { altText += (i + 1) + '. ' + v + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: altText.slice(0, 1000) } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Claude AI Chain-of-Thought + One CLI' }] });

const fallback = 'Reasoning: ' + (ai.keyTakeaway || ai.conclusion || '').slice(0, 150);
return { blocks, fallback };
